    coefficients: Vec<f64>,
    fitted_values: Vec<f64>,
    residuals: Vec<f64>,
    /// Number of observations
    n_obs: usize,
    /// Matrix rank (for rank-deficient matrices)
    rank: usize,
    /// QR decomposition for statistical inference
    qr: faer::qr::col_piv::Qr<f64>,
    // x_matrix: Mat<f64>, // No longer needed if qr is stored
}
// ... context_end_text

// In Lm::fit_internal (around line 294)
