            qr, // Store the decomposition
        })
// ... context_end_text

// In LmFit::summary (around line 604)
// ... context_start_text
        // Calculate variance-covariance matrix: σ² * (X'X)^(-1)
        // This is equivalent to σ² * (R'R)^-1 = σ² * R^-1 * (R')^-1
        // We can solve R' * B = I for B, then VarCovar = σ² * R^-1 * B
        // A more direct way is to solve for (X'X)^-1 using the QR of X.
        let r_matrix = self.qr.R();
        let r_inv = r_matrix.inverse(); // faer can invert triangular matrices efficiently
        let xtx_inv = &r_inv * r_inv.transpose();

        // Standard errors are sqrt of diagonal elements of σ² * (X'X)^(-1)
// ... context_end_text
